import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { phongAPI, thanhToanAPI, yeuCauAPI } from '../services/api';
import { buildPhongAddress } from '../utils/location';
import './QuanLyPhong.css';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

export default function QuanLyPhong() {
  const navigate = useNavigate();
  const [phongs, setPhongs] = useState([]);
  const [yeuCaus, setYeuCaus] = useState({});
  const [selectedPhong, setSelectedPhong] = useState(null);
  const [loading, setLoading] = useState(true);
  const [deletingPhongId, setDeletingPhongId] = useState(null);

  const fetchPhongs = async () => {
    setLoading(true);
    try {
      const res = await phongAPI.layPhongCuaToi();
      setPhongs(res.data.data || []);
    } catch {
      toast.error('Không tải được danh sách phòng');
    }
    setLoading(false);
  };

  const fetchYeuCau = async maPhong => {
    try {
      const res = await yeuCauAPI.layCuaPhong(maPhong);
      setYeuCaus(prev => ({ ...prev, [maPhong]: res.data.data || [] }));
    } catch {
      toast.error('Không tải được yêu cầu tham gia');
    }
  };

  useEffect(() => {
    fetchPhongs();
  }, []);

  const handleDuyet = async (maYeuCau, chapNhan, maPhong) => {
    try {
      await yeuCauAPI.duyet(maYeuCau, chapNhan);
      toast.success(chapNhan ? 'Đã chấp nhận yêu cầu!' : 'Đã từ chối yêu cầu!');
      fetchPhongs();
      fetchYeuCau(maPhong);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  };

  const handleChiaTien = async maPhong => {
    try {
      await thanhToanAPI.chiaTien(maPhong);
      toast.success('Đã tạo hóa đơn chia tiền cho các thành viên!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  };

  const handleDoiTrangThai = async (maPhong, trangThai) => {
    try {
      await phongAPI.capNhat(maPhong, { trangThai });
      toast.success('Cập nhật trạng thái thành công!');
      fetchPhongs();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  };

  const handleDeletePhong = async maPhong => {
    if (!window.confirm('Bạn có chắc muốn xóa phòng này không?')) return;

    setDeletingPhongId(maPhong);
    try {
      await phongAPI.xoa(maPhong);
      setPhongs(current => current.filter(phong => phong.maPhong !== maPhong));
      setSelectedPhong(current => (current === maPhong ? null : current));
      setYeuCaus(current => {
        const next = { ...current };
        delete next[maPhong];
        return next;
      });
      toast.success('Đã xóa phòng thành công');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xóa phòng thất bại');
    }
    setDeletingPhongId(null);
  };

  if (loading) return <div className="spinner" />;

  return (
    <div className="container page-wrapper">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
        <h1 className="section-title" style={{ marginBottom: 0 }}>Quản lý phòng</h1>
        <Link to="/tao-phong" className="btn btn-primary">Thêm phòng mới</Link>
      </div>

      {phongs.length === 0 ? (
        <div className="empty-state card">
          <div className="card-body">
            <div className="empty-state-icon">🏠</div>
            <p>Bạn chưa có phòng nào. <Link to="/tao-phong">Tạo phòng ngay!</Link></p>
          </div>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
          {phongs.map(phong => (
            <div key={phong.maPhong} className="card phong-manage-card">
              <div className="phong-manage-header">
                <div>
                  <h3>{phong.title}</h3>
                  <div style={{ color: 'var(--text-muted)', fontSize: 14, marginTop: 4 }}>
                    {buildPhongAddress(phong)} · {fmt(phong.giaTien)}/tháng
                  </div>
                </div>

                <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                  <span className={`badge ${
                    phong.trangThai === 'San sang'
                      ? 'badge-success'
                      : phong.trangThai === 'Da day'
                        ? 'badge-danger'
                        : 'badge-warning'
                  }`}>
                    {phong.trangThai === 'San sang'
                      ? 'Sẵn sàng'
                      : phong.trangThai === 'Da day'
                        ? 'Đã đầy'
                        : 'Bảo trì'}
                  </span>

                  <select
                    className="form-control"
                    style={{ width: 'auto', padding: '6px 10px', fontSize: 13 }}
                    value={phong.trangThai}
                    onChange={e => handleDoiTrangThai(phong.maPhong, e.target.value)}
                  >
                    <option value="San sang">Sẵn sàng</option>
                    <option value="Da day">Đã đầy</option>
                    <option value="Bao tri">Bảo trì</option>
                  </select>
                </div>
              </div>

              <div className="phong-manage-body">
                <div className="members-section">
                  <h4>Thành viên ({phong.soNguoiHienTai}/{phong.soNguoiToiDa})</h4>
                  <div className="members-list">
                    {phong.danhSachThanhVien?.map(member => (
                      <div key={member.maNguoiDung} className="member-item">
                        <img
                          src={member.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(member.hoTen)}&background=12355B&color=fff&size=32`}
                          className="avatar avatar-sm"
                          alt=""
                        />
                        <span>{member.hoTen}</span>
                      </div>
                    ))}
                    {phong.danhSachThanhVien?.length === 0 && (
                      <p style={{ color: 'var(--text-muted)', fontSize: 13 }}>Chưa có thành viên</p>
                    )}
                  </div>
                </div>

                <div className="phong-actions">
                  <button
                    className="btn btn-outline btn-sm"
                    onClick={() => navigate(`/phong/${phong.maPhong}/chinh-sua`)}
                  >
                    Chỉnh sửa phòng
                  </button>
                  <button
                    className="btn btn-danger btn-sm"
                    onClick={() => handleDeletePhong(phong.maPhong)}
                    disabled={deletingPhongId === phong.maPhong}
                  >
                    {deletingPhongId === phong.maPhong ? 'Đang xóa...' : 'Xóa phòng'}
                  </button>
                  <button
                    className="btn btn-secondary btn-sm"
                    onClick={() => {
                      fetchYeuCau(phong.maPhong);
                      setSelectedPhong(current => (current === phong.maPhong ? null : phong.maPhong));
                    }}
                  >
                    Xem yêu cầu
                  </button>
                  <button className="btn btn-success btn-sm" onClick={() => handleChiaTien(phong.maPhong)}>
                    Chia tiền phòng
                  </button>
                </div>
              </div>

              {selectedPhong === phong.maPhong && (
                <div className="yeu-cau-panel">
                  <h4>Yêu cầu tham gia</h4>
                  {(yeuCaus[phong.maPhong] || []).length === 0 ? (
                    <p style={{ color: 'var(--text-muted)', fontSize: 13 }}>Chưa có yêu cầu nào.</p>
                  ) : (
                    (yeuCaus[phong.maPhong] || []).map(yc => (
                      <div key={yc.maYeuCau} className="yeu-cau-item">
                        <img
                          src={yc.avatarNguoiDung || `https://ui-avatars.com/api/?name=${encodeURIComponent(yc.tenNguoiDung)}&size=40`}
                          className="avatar avatar-sm"
                          alt=""
                        />
                        <div style={{ flex: 1 }}>
                          <strong>{yc.tenNguoiDung}</strong>
                          {yc.moTa && <p style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 2 }}>{yc.moTa}</p>}
                        </div>
                        <span className={`badge ${
                          yc.trangThai === 'Chap nhan'
                            ? 'badge-success'
                            : yc.trangThai === 'Tu choi'
                              ? 'badge-danger'
                              : 'badge-warning'
                        }`}>
                          {yc.trangThai === 'Chap nhan'
                            ? 'Đã chấp nhận'
                            : yc.trangThai === 'Tu choi'
                              ? 'Đã từ chối'
                              : 'Chờ duyệt'}
                        </span>
                        {yc.trangThai === 'Cho duyet' && (
                          <div style={{ display: 'flex', gap: 6 }}>
                            <button className="btn btn-success btn-sm" onClick={() => handleDuyet(yc.maYeuCau, true, phong.maPhong)}>Duyệt</button>
                            <button className="btn btn-danger btn-sm" onClick={() => handleDuyet(yc.maYeuCau, false, phong.maPhong)}>Từ chối</button>
                          </div>
                        )}
                      </div>
                    ))
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
